@using sv_981fec1df93e4ea9bb61ea4daad8de20.Models

<div class="step-indicator d-flex align-items-center mb-4">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var step = i;
        var status = step < CurrentStep ? "completed" : step == CurrentStep ? "active" : "future";

        <div class="step @status" @onclick="() => HandleClick(step)" role="button" tabindex="0">
            <div class="step-circle">
                @if (step < CurrentStep)
                {
                    <span>✓</span>
                }
                else
                {
                    <span>@(step + 1)</span>
                }
            </div>
            <div class="step-label">@StepNames[step]</div>
        </div>

        @if (i < StepNames.Length - 1)
        {
            <div class="step-connector @(step < CurrentStep ? "completed" : "")"></div>
        }
    }
</div>

@code {
    private static readonly string[] StepNames =
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private async Task HandleClick(int step)
    {
        if (step < CurrentStep)
        {
            await OnStepClicked.InvokeAsync(step);
        }
    }
}

.step-indicator {
    gap: 0;
    flex-wrap: nowrap;
    justify-content: center;
}

.step {
    display: flex;
    flex-direction: column;
    align-items: center;
    min-width: 90px;
    cursor: default;
    opacity: 0.4;
    transition: opacity 0.2s;
}

.step.completed {
    cursor: pointer;
    opacity: 1;
}

.step.active {
    opacity: 1;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.85rem;
    border: 2px solid #dee2e6;
    background: #fff;
    color: #6c757d;
    transition: all 0.2s;
}

.step.active .step-circle {
    border-color: #0d6efd;
    background: #0d6efd;
    color: #fff;
}

.step.completed .step-circle {
    border-color: #198754;
    background: #198754;
    color: #fff;
}

.step-label {
    margin-top: 6px;
    font-size: 0.75rem;
    text-align: center;
    white-space: nowrap;
}

.step-connector {
    flex: 1;
    height: 2px;
    background: #dee2e6;
    align-self: flex-start;
    margin-top: 17px;
    min-width: 20px;
    transition: background 0.2s;
}

.step-connector.completed {
    background: #198754;
}

@using sv_981fec1df93e4ea9bb61ea4daad8de20.Models

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Position @(Index + 1)</h6>
            @if (CanRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="HandleRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Company Name *</label>
                <input type="text" class="form-control" value="@Entry.Company"
                       @onchange="e => { Entry.Company = e.Value?.ToString() ?? string.Empty; NotifyChanged(); }" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title *</label>
                <input type="text" class="form-control" value="@Entry.Title"
                       @onchange="e => { Entry.Title = e.Value?.ToString() ?? string.Empty; NotifyChanged(); }" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Start Date *</label>
                <input type="date" class="form-control"
                       value="@(Entry.StartDate?.ToString("yyyy-MM-dd"))"
                       @onchange="e => { Entry.StartDate = DateTime.TryParse(e.Value?.ToString(), out var d) ? d : null; NotifyChanged(); }" />
            </div>
            <div class="col-md-4">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control"
                       value="@(Entry.EndDate?.ToString("yyyy-MM-dd"))"
                       disabled="@Entry.IsCurrent"
                       @onchange="e => { Entry.EndDate = DateTime.TryParse(e.Value?.ToString(), out var d) ? d : null; NotifyChanged(); }" />
            </div>
            <div class="col-md-4 d-flex align-items-end">
                <div class="form-check mb-2">
                    <input type="checkbox" class="form-check-input" id="current-@Index"
                           checked="@Entry.IsCurrent"
                           @onchange="e => { Entry.IsCurrent = (bool)(e.Value ?? false); if (Entry.IsCurrent) Entry.EndDate = null; NotifyChanged(); }" />
                    <label class="form-check-label" for="current-@Index">Currently working here</label>
                </div>
            </div>
            <div class="col-12">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="3" value="@Entry.Description"
                          @onchange="e => { Entry.Description = e.Value?.ToString() ?? string.Empty; NotifyChanged(); }"></textarea>
            </div>
        </div>
    </div>
</div>

