.step-indicator {
    gap: 0;
    flex-wrap: nowrap;
    justify-content: center;
}

.step {
    display: flex;
    flex-direction: column;
    align-items: center;
    min-width: 90px;
    cursor: default;
    opacity: 0.4;
    transition: opacity 0.2s;
}

.step.completed {
    cursor: pointer;
    opacity: 1;
}

.step.active {
    opacity: 1;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.85rem;
    border: 2px solid #dee2e6;
    background: #fff;
    color: #6c757d;
    transition: all 0.2s;
}

.step.active .step-circle {
    border-color: #0d6efd;
    background: #0d6efd;
    color: #fff;
}

.step.completed .step-circle {
    border-color: #198754;
    background: #198754;
    color: #fff;
}

.step-label {
    margin-top: 6px;
    font-size: 0.75rem;
    text-align: center;
    white-space: nowrap;
}

.step-connector {
    flex: 1;
    height: 2px;
    background: #dee2e6;
    align-self: flex-start;
    margin-top: 17px;
    min-width: 20px;
    transition: background 0.2s;
}

.step-connector.completed {
    background: #198754;
}

