@using sv_981fec1df93e4ea9bb61ea4daad8de20.Models
@using sv_981fec1df93e4ea9bb61ea4daad8de20.Services

@inject IApplicationService ApplicationService

<h4 class="mb-3">Personal Information</h4>

<EditForm Model="Model" OnValidSubmit="HandleNext" FormName="personal-info">
    <DataAnnotationsValidator />

    <div class="row g-3">
        <div class="col-md-6">
            <label class="form-label">Full Name *</label>
            <InputText @bind-Value="Model.FullName" class="form-control" />
            <ValidationMessage For="() => Model.FullName" />
        </div>
        <div class="col-md-6">
            <label class="form-label">Email *</label>
            <InputText @bind-Value="Model.Email" class="form-control" />
            <ValidationMessage For="() => Model.Email" />
            @if (!string.IsNullOrEmpty(emailError))
            {
                <div class="text-danger mt-1">@emailError</div>
            }
        </div>
        <div class="col-md-6">
            <label class="form-label">Phone *</label>
            <InputText @bind-Value="Model.Phone" class="form-control" />
            <ValidationMessage For="() => Model.Phone" />
        </div>
        <div class="col-md-6">
            <label class="form-label">Address *</label>
            <InputText @bind-Value="Model.Address" class="form-control" />
            <ValidationMessage For="() => Model.Address" />
        </div>
    </div>

    <div class="d-flex justify-content-end mt-4">
        <button type="submit" class="btn btn-primary" disabled="@isValidating">
            @if (isValidating)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                <span>Validating…</span>
            }
            else
            {
                <span>Next →</span>
            }
        </button>
    </div>
</EditForm>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }

    private string? emailError;
    private bool isValidating;

    private async Task HandleNext()
    {
        emailError = null;
        isValidating = true;

        try
        {
            var isValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!isValid)
            {
                emailError = "This email address could not be verified.";
                return;
            }

            await OnNext.InvokeAsync();
        }
        finally
        {
            isValidating = false;
        }
    }
}

@using sv_981fec1df93e4ea9bb61ea4daad8de20.Models

<h4 class="mb-3">Work History</h4>

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    <WorkEntryForm Entry="Entries[index]"
                   Index="index"
                   CanRemove="Entries.Count > 1"
                   OnChanged="StateHasChanged"
                   OnRemoved="() => RemoveEntry(index)" />
}

<button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

@if (!string.IsNullOrEmpty(validationError))
{
    <div class="alert alert-danger">@validationError</div>
}

<div class="d-flex justify-content-between mt-3">
    <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">← Back</button>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next →</button>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? validationError;

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
        {
            Entries.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        validationError = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) ||
                string.IsNullOrWhiteSpace(entry.Title) ||
                entry.StartDate is null)
            {
                validationError = "Please fill in the company name, job title, and start date for each position.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@using sv_981fec1df93e4ea9bb61ea4daad8de20.Models

<h4 class="mb-3">References</h4>

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    <ReferenceForm Reference="References[index]"
                   Index="index"
                   CanRemove="References.Count > 2"
                   OnChanged="StateHasChanged"
                   OnRemoved="() => RemoveReference(index)" />
}

@if (References.Count < 3)
{
    <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddReference">
        + Add Reference
    </button>
}

@if (!string.IsNullOrEmpty(validationError))
{
    <div class="alert alert-danger">@validationError</div>
}

<div class="d-flex justify-content-between mt-3">
    <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">← Back</button>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next →</button>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? validationError;

    private void AddReference()
    {
        if (References.Count < 3)
        {
            References.Add(new ReferenceModel());
        }
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
        {
            References.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        validationError = null;

        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) ||
                string.IsNullOrWhiteSpace(r.Relationship) ||
                string.IsNullOrWhiteSpace(r.Email) ||
                string.IsNullOrWhiteSpace(r.Phone))
            {
                validationError = "Please fill in all fields for each reference.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@using sv_981fec1df93e4ea9bb61ea4daad8de20.Models

<h4 class="mb-3">Review Your Application</h4>

@* --- Personal Info --- *@
<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Personal Information</strong>
        <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(0)">Edit</button>
    </div>
    <div class="card-body">
        <dl class="row mb-0">
            <dt class="col-sm-3">Full Name</dt>
            <dd class="col-sm-9">@Personal.FullName</dd>
            <dt class="col-sm-3">Email</dt>
            <dd class="col-sm-9">@Personal.Email</dd>
            <dt class="col-sm-3">Phone</dt>
            <dd class="col-sm-9">@Personal.Phone</dd>
            <dt class="col-sm-3">Address</dt>
            <dd class="col-sm-9">@Personal.Address</dd>
        </dl>
    </div>
</div>

@* --- Work History --- *@
<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Work History</strong>
        <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(1)">Edit</button>
    </div>
    <div class="card-body">
        @foreach (var entry in WorkEntries)
        {
            <div class="mb-3">
                <h6 class="mb-1">@entry.Title at @entry.Company</h6>
                <div class="text-muted small">
                    @entry.StartDate?.ToString("MMM yyyy") –
                    @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                </div>
                @if (!string.IsNullOrWhiteSpace(entry.Description))
                {
                    <p class="mt-1 mb-0">@entry.Description</p>
                }
            </div>
        }
    </div>
</div>

@* --- References --- *@
<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>References</strong>
        <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(2)">Edit</button>
    </div>
    <div class="card-body">
        @foreach (var r in References)
        {
            <div class="mb-2">
                <strong>@r.Name</strong> — @r.Relationship<br />
                <span class="text-muted">@r.Email · @r.Phone</span>
            </div>
        }
    </div>
</div>

@* --- Cover Letter --- *@
<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Cover Letter</strong>
        <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(3)">Edit</button>
    </div>
    <div class="card-body">
        <p style="white-space: pre-wrap;">@CoverLetter</p>
    </div>
</div>

@* --- Submit --- *@
@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="alert alert-danger">@errorMessage</div>
}

<div class="d-flex justify-content-between mt-4">
    <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">← Back</button>
    <button type="button" class="btn btn-success btn-lg" disabled="@isSubmitting" @onclick="HandleSubmit">
        @if (isSubmitting)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            <span>Submitting…</span>
        }
        else
        {
            <span>Submit Application</span>
        }
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<int> OnEdit { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }

    private bool isSubmitting;
    private string? errorMessage;

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        errorMessage = null;

        try
        {
            await OnSubmit.InvokeAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

@using sv_981fec1df93e4ea9bb61ea4daad8de20.Models
@using sv_981fec1df93e4ea9bb61ea4daad8de20.Services

@inject IApplicationService ApplicationService

<h4 class="mb-3">Personal Information</h4>

<EditForm Model="Model" OnValidSubmit="HandleNext" FormName="personal-info">
    <DataAnnotationsValidator />

    <div class="row g-3">
        <div class="col-md-6">
            <label class="form-label">Full Name *</label>
            <InputText @bind-Value="Model.FullName" class="form-control" />
            <ValidationMessage For="() => Model.FullName" />
        </div>
        <div class="col-md-6">
            <label class="form-label">Email *</label>
            <InputText @bind-Value="Model.Email" class="form-control" />
            <ValidationMessage For="() => Model.Email" />
            @if (!string.IsNullOrEmpty(emailError))
            {
                <div class="text-danger mt-1">@emailError</div>
            }
        </div>
        <div class="col-md-6">
            <label class="form-label">Phone *</label>
            <InputText @bind-Value="Model.Phone" class="form-control" />
            <ValidationMessage For="() => Model.Phone" />
        </div>
        <div class="col-md-6">
            <label class="form-label">Address *</label>
            <InputText @bind-Value="Model.Address" class="form-control" />
            <ValidationMessage For="() => Model.Address" />
        </div>
    </div>

    <div class="d-flex justify-content-end mt-4">
        <button type="submit" class="btn btn-primary" disabled="@isValidating">
            @if (isValidating)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                <span>Validating…</span>
            }
            else
            {
                <span>Next →</span>
            }
        </button>
    </div>
</EditForm>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }

    private string? emailError;
    private bool isValidating;

    private async Task HandleNext()
    {
        emailError = null;
        isValidating = true;

        try
        {
            var isValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!isValid)
            {
                emailError = "This email address could not be verified.";
                return;
            }

            await OnNext.InvokeAsync();
        }
        finally
        {
            isValidating = false;
        }
    }
}

