@using sv_981fec1df93e4ea9bb61ea4daad8de20.Models
@using sv_981fec1df93e4ea9bb61ea4daad8de20.Services

@inject IApplicationService ApplicationService

<h4 class="mb-3">Personal Information</h4>

<EditForm Model="Model" OnValidSubmit="HandleNext" FormName="personal-info">
    <DataAnnotationsValidator />

    <div class="row g-3">
        <div class="col-md-6">
            <label class="form-label">Full Name *</label>
            <InputText @bind-Value="Model.FullName" class="form-control" />
            <ValidationMessage For="() => Model.FullName" />
        </div>
        <div class="col-md-6">
            <label class="form-label">Email *</label>
            <InputText @bind-Value="Model.Email" class="form-control" />
            <ValidationMessage For="() => Model.Email" />
            @if (!string.IsNullOrEmpty(emailError))
            {
                <div class="text-danger mt-1">@emailError</div>
            }
        </div>
        <div class="col-md-6">
            <label class="form-label">Phone *</label>
            <InputText @bind-Value="Model.Phone" class="form-control" />
            <ValidationMessage For="() => Model.Phone" />
        </div>
        <div class="col-md-6">
            <label class="form-label">Address *</label>
            <InputText @bind-Value="Model.Address" class="form-control" />
            <ValidationMessage For="() => Model.Address" />
        </div>
    </div>

    <div class="d-flex justify-content-end mt-4">
        <button type="submit" class="btn btn-primary" disabled="@isValidating">
            @if (isValidating)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                <span>Validating…</span>
            }
            else
            {
                <span>Next →</span>
            }
        </button>
    </div>
</EditForm>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }

    private string? emailError;
    private bool isValidating;

    private async Task HandleNext()
    {
        emailError = null;
        isValidating = true;

        try
        {
            var isValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!isValid)
            {
                emailError = "This email address could not be verified.";
                return;
            }

            await OnNext.InvokeAsync();
        }
        finally
        {
            isValidating = false;
        }
    }
}

