@page "/apply"
@rendermode InteractiveServer

@using sv_981fec1df93e4ea9bb61ea4daad8de20.Models
@using sv_981fec1df93e4ea9bb61ea4daad8de20.Services

@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="text-center mb-4">Job Application</h2>

    @if (isSubmitted)
    {
        <div class="alert alert-success text-center">
            <h4 class="alert-heading">Application Submitted!</h4>
            <p>Your application has been received. Your confirmation number is:</p>
            <p class="display-6 fw-bold">@applicationId</p>
            <hr />
            <p class="mb-0">We will be in touch soon. Thank you!</p>
        </div>
    }
    else
    {
        <StepIndicator CurrentStep="currentStep" OnStepClicked="GoToStep" />

        @switch (currentStep)
        {
            case 0:
                <PersonalInfoStep Model="personalInfo" OnNext="NextStep" />
                break;
            case 1:
                <WorkHistoryStep Entries="workEntries" OnNext="NextStep" OnBack="PreviousStep" />
                break;
            case 2:
                <ReferencesStep References="references" OnNext="NextStep" OnBack="PreviousStep" />
                break;
            case 3:
                <CoverLetterStep CoverLetter="@coverLetter"
                                 CoverLetterChanged="v => coverLetter = v"
                                 OnNext="NextStep"
                                 OnBack="PreviousStep" />
                break;
            case 4:
                <ReviewStep Personal="personalInfo"
                            WorkEntries="workEntries"
                            References="references"
                            CoverLetter="@coverLetter"
                            OnEdit="GoToStep"
                            OnBack="PreviousStep"
                            OnSubmit="SubmitApplication" />
                break;
        }
    }
</div>

@code {
    private int currentStep;
    private bool isSubmitted;
    private int applicationId;

    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = new() { new WorkEntryModel() };
    private List<ReferenceModel> references = new() { new ReferenceModel(), new ReferenceModel() };
    private string coverLetter = "";

    private void NextStep() => currentStep++;
    private void PreviousStep() => currentStep--;
    private void GoToStep(int step) => currentStep = step;

    private async Task SubmitApplication()
    {
        var application = new JobApplication(
            personalInfo.ToRecord(),
            new WorkHistory(workEntries.Select(e => e.ToRecord()).ToList()),
            references.Select(r => r.ToRecord()).ToList(),
            coverLetter);

        applicationId = await ApplicationService.SubmitApplicationAsync(application);
        isSubmitted = true;
    }
}

